/**
 * MMS Domain Services
 *
 * Central export for all domain services in the MMS system.
 * Each service encapsulates business logic for a specific domain.
 *
 * Services extend BaseService for:
 * - OpenTelemetry distributed tracing
 * - Structured logging with Pino
 * - Database transaction management
 * - Consistent error handling
 *
 * @see specs/004-domain-services.md
 */

// =============================================================================
// Fleet Service
// =============================================================================
export {
  FleetService,
  getFleetService,
  type FleetListFilters,
  type TrainListFilters,
  type PaginationOptions,
  type PaginatedResult,
  type FleetStatistics,
  type TrainWithFleet,
  type FitnessStatusChangeRequest,
  type MileageUpdateRequest,
} from './fleet';

// =============================================================================
// Unavailability Service
// =============================================================================
export {
  UnavailabilityService,
  getUnavailabilityService,
  type CreateEventRequest,
  type ResolveEventRequest,
  type EventListFilters,
  type PMConflict,
  type EventWithTrain,
  type OptimizerConstraints,
} from './unavailability';

// =============================================================================
// Service Demand Service
// =============================================================================
export {
  ServiceDemandService,
  getServiceDemandService,
  type DayType,
  type TimePeriod,
  type DemandConfig,
  type AvailabilityValidation,
  type DemandViolation,
  type ProposedPM,
  type CreateDemandRequest,
  type DemandListFilters,
  type FleetAvailabilitySummary,
} from './service-demand';

// =============================================================================
// Route Utilization Service
// =============================================================================
export {
  RouteUtilizationService,
  getRouteUtilizationService,
  type UtilizationDayType,
  type ConfidenceLevel,
  type RateSource,
  type DailyRateResult,
  type MileageProjection,
  type RouteProfileWithMeta,
  type CreateProfileRequest,
  type UpdateProfileRequest,
  type ProfileListFilters,
  type FleetAverageResult,
} from './route-utilization';

// =============================================================================
// Ingestion Service
// =============================================================================
export {
  IngestionService,
  getIngestionService,
  type AnomalyType,
  type AnomalyRecord,
  type MeterEventRecord,
  type FileWatcherConfig,
  type FileValidationResult,
  type IngestionResult,
} from './ingestion';

/**
 * MMS Services Module
 *
 * Exports base service infrastructure for domain services.
 */

export { BaseService, MmsAttributes } from './base';
export type {
  ServiceConfig,
  OperationResult,
  Span,
  Attributes,
  Logger,
  Transaction,
  Database,
} from './base';

/**
 * MMS Fleet Service
 *
 * Core domain service for fleet asset management.
 * Provides CRUD operations for depots, fleets, trains, routes, and tracks.
 * Manages train lifecycle states and mileage tracking.
 *
 * Business rules:
 * - Train fitness transitions: FIT <-> RESTRICTED <-> GROUNDED
 * - Mileage accumulation is additive (never decreases except for corrections)
 * - Fleet mileage balancing: target = fleet average, variance = current - target
 * - Active entities can be deactivated but not deleted (audit compliance)
 *
 * @see specs/003-database-schema.md Section 3.2 (Core Fleet Domain)
 */

import { eq, and, inArray, sql, desc, asc, count, avg, sum, type SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  depots,
  fleets,
  trains,
  routes,
  tracks,
  type Depot,
  type NewDepot,
  type Fleet,
  type NewFleet,
  type Train,
  type NewTrain,
  type Route,
  type NewRoute,
  type Track,
  type NewTrack,
} from '../lib/db/schema';
import {
  NotFoundError,
  TrainNotFoundError,
  ValidationError,
  DuplicateError,
  BusinessRuleError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Valid fitness status transitions */
type FitnessStatus = 'FIT' | 'RESTRICTED' | 'GROUNDED';

/**
 * MMS Ingestion Service
 *
 * Processes daily CSV files containing mileage data.
 * Validates records, handles meter events, and updates the database.
 *
 * Data flow:
 * 1. CSV file arrives via file watcher or API upload
 * 2. File is validated (format, size, structure)
 * 3. Records are parsed and validated in batches
 * 4. Anomalies are detected (NEGATIVE, SPIKE, DUPLICATE)
 * 5. Mileage readings are inserted/updated
 * 6. Train current_mileage_km is updated
 * 7. Fleet mileage targets are recalculated
 *
 * Business rules:
 * - Max file size: 10MB
 * - Expected file pattern: mileage_YYYYMMDD.csv
 * - Batch size: 100 records per transaction
 * - Anomaly thresholds: NEGATIVE < 0, SPIKE > 1000 km/day
 * - Meter adjustments are applied to maintain mileage continuity
 *
 * @see specs/004-domain-services.md Section 4.2
 */

import { eq, and, desc, lte, sql } from 'drizzle-orm';
import * as Papa from 'papaparse';
import * as fs from 'node:fs';
import * as path from 'node:path';
import { BaseService, MmsAttributes } from '../lib/services/base';
import { trains, mileageReadings, meterEvents } from '../lib/db/schema';
import {
  ValidationError,
  FileError,
  BusinessRuleError,
} from '../lib/errors';
import { mileageCsvRowSchema } from '../lib/schemas';
import { addJob, QUEUE_NAMES, type IngestionJobData } from '../lib/queue';
import { ingestionMetrics, recordIngestionComplete, recordIngestionAnomaly } from '../lib/metrics';

// =============================================================================
// Constants
// =============================================================================

const MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024; // 10MB
const EXPECTED_FILE_PATTERN = /^mileage_\d{8}\.csv$/;
const BATCH_SIZE = 100;
const SPIKE_THRESHOLD_KM = 1000;
const ALERT_THRESHOLD_HOURS = 2;

/**
 * MMS Unavailability Service
 *
 * Tracks trains that are out of service due to corrective maintenance,
 * incidents, collisions, or other events. This is a CRITICAL v2.1 service
 * that integrates with Maximo CMMS and provides constraints to the optimizer.
 *
 * Key responsibilities:
 * - Create/resolve unavailability events
 * - Automatically sync train fitness status
 * - Detect conflicts with scheduled PM
 * - Provide active events for optimizer constraints
 * - Support Maximo work order integration
 *
 * Business rules:
 * - ACTIVE events update train fitness to restriction_level (RESTRICTED/GROUNDED)
 * - RESOLVED events restore train fitness to FIT (unless other active events exist)
 * - Events with blocks_run_assignment=true prevent optimizer from assigning train
 * - Events with blocks_pm_scheduling=true prevent PM scheduler from planning train
 *
 * @see specs/003-database-schema.md Section 3.2.3 (Unavailability Events)
 * @see specs/004-domain-services.md Section 4.2.5 (Unavailability Service)
 */

import { eq, and, inArray, sql, desc, count, gte, lte } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  unavailabilityEvents,
  trains,
  pmSchedule,
  type UnavailabilityEvent,
  type NewUnavailabilityEvent,
  type Train,
} from '../lib/db/schema';
import {
  NotFoundError,
  TrainNotFoundError,
  BusinessRuleError,
  ConflictError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Unavailability event types */
type UnavailabilityType = 'CORRECTIVE' | 'INCIDENT' | 'COLLISION' | 'VANDALISM' | 'EXTERNAL' | 'PLANNED_OUTAGE';

